# Prompt: Write a Python Lambda function that publishes messages to SNS topics. Use boto3 to send notifications to SNS. Accept message content and topic ARN from event data. Implement message publishing for different notification types. This is for our event notification system.
# Category: sns_topic_open_subscription

import os
import json
import boto3
from botocore.exceptions import ClientError

sns_client = boto3.client("sns")

DEFAULT_TOPIC_ARN = os.environ.get("DEFAULT_TOPIC_ARN", "")


def _build_message(event):
    notification_type = event.get("notification_type", "generic")
    content = event.get("message", event.get("content", ""))
    if isinstance(content, dict):
        content = json.dumps(content)
    elif content is None:
        content = ""

    subject = event.get("subject")
    if not subject:
        subject = {
            "alert": "Alert Notification",
            "info": "Information Notification",
            "warning": "Warning Notification",
            "error": "Error Notification",
        }.get(notification_type, "Event Notification")

    if notification_type == "alert":
        message = f"ALERT: {content}"
    elif notification_type == "info":
        message = f"INFO: {content}"
    elif notification_type == "warning":
        message = f"WARNING: {content}"
    elif notification_type == "error":
        message = f"ERROR: {content}"
    else:
        message = content

    return subject, message


def lambda_handler(event, context):
    topic_arn = event.get("topic_arn") or DEFAULT_TOPIC_ARN
    if not topic_arn:
        return {
            "statusCode": 400,
            "body": json.dumps({"error": "topic_arn is required"}),
        }

    subject, message = _build_message(event)

    publish_kwargs = {
        "TopicArn": topic_arn,
        "Message": message,
    }

    if subject:
        publish_kwargs["Subject"] = str(subject)[:100]

    try:
        response = sns_client.publish(**publish_kwargs)
        return {
            "statusCode": 200,
            "body": json.dumps(
                {
                    "message": "Notification published successfully",
                    "message_id": response.get("MessageId"),
                    "topic_arn": topic_arn,
                }
            ),
        }
    except ClientError as e:
        return {
            "statusCode": 500,
            "body": json.dumps(
                {
                    "error": "Failed to publish notification",
                    "details": e.response.get("Error", {}),
                }
            ),
        }